import urllib.request
import json

url = "https://api.github.com/repos/divakarpandey07/AI-Palmistry-pro/actions/runs"
req = urllib.request.Request(url, headers={
    "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)",
    "Accept": "application/vnd.github.v3+json"
})

try:
    with urllib.request.urlopen(req) as resp:
        data = json.loads(resp.read().decode("utf-8"))
        runs = data.get("workflow_runs", [])
        if runs:
            latest_run = runs[0]
            print(f"Latest Run ID: {latest_run['id']} | SHA: {latest_run['head_sha'][:7]} | Conclusion: {latest_run['conclusion']}")
            jobs_url = latest_run['jobs_url']
            req_j = urllib.request.Request(jobs_url, headers={
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)",
                "Accept": "application/vnd.github.v3+json"
            })
            with urllib.request.urlopen(req_j) as resp_j:
                jdata = json.loads(resp_j.read().decode("utf-8"))
                for j in jdata.get("jobs", []):
                    print(f"Job: {j['name']} | Conclusion: {j['conclusion']}")
                    for step in j.get("steps", []):
                        print(f"   Step: {step['name']} | Conclusion: {step.get('conclusion')}")
except Exception as e:
    print(f"Error querying API: {e}")
